window.onload = function() {
    // We bypass the default behavior and point directly
    // to the configuration JSON generated by the SwaggerConfig.class
    window.ui = SwaggerUIBundle({
        configUrl: "/nexus-backend/v3/api-docs/swagger-config",
        dom_id: '#swagger-ui',
        deepLinking: true,
        presets: [
            SwaggerUIBundle.presets.apis,
            SwaggerUIStandalonePreset
        ],
        plugins: [
            SwaggerUIBundle.plugins.DownloadUrl
        ],
        layout: "StandaloneLayout"
    });
};
